mapper.select:
	SELECT count(*) AS CNT
	  FROM XBOLTADM.TB_ITEM 
	 WHERE ItemTypeCode = #{itemTypeCode} 		       
	  			  		
       		AND Identifier LIKE #{identifier}
	  			       
	  			  		
       		AND ProjectID = #{projectID}

SELECT Row_Number()OVER(ORDER BY TI.Identifier) as RNUM, REPLACE(TI.Identifier,' ','!') AS Identifier, TIA.PlainText, TI.ItemID, TIC.FromItemID, TM.Name AS AuthorNm, TTT.Name AS TeamNm, (SELECT Max(Version) FROM XBOLTADM.TB_CHANGE_SET WHERE ItemID = TI.ItemID) AS Version, STUFF(( SELECT CHAR(10) + A.FileRealName FROM ( SELECT FileRealName FROM XBOLTADM.TB_FILE WHERE DocumentID = TI.ItemID )A FOR XML PATH('') ),1,1,'') AS FileList , STUFF(( SELECT CHAR(10) + A.ItemName FROM ( SELECT TICI.Identifier + ' ' + TICA.PlainText AS ItemName FROM XBOLTADM.TB_ITEM TIC LEFT OUTER JOIN XBOLTADM.TB_ITEM TICI ON TICI.itemid = TIC.FromItemID AND TICI.CategoryCode = 'OJ' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TICA ON TICI.ItemID = TICA.ItemID AND TICA.AttrTypeCode = 'AT00001' AND TICA.LanguageID = #{languageID} WHERE TI.ItemID = TIC.ToItemID AND TIC.CategoryCode = 'CN' AND TIC.Deleted = 0 )A FOR XML PATH('') ),1,1,'') AS ConItemList
FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM TIC ON TI.ItemID = TIC.ToItemID AND TIC.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTT ON TI.OwnerTeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} WHERE TI.ItemTypeCode = 'OJ00007' AND TI.Identifier not like '%(P)%' AND TI.Deleted = 0
AND TIC.FromItemID = #{fromItemID}
AND TI.ItemID = #{itemID}
ORDER BY TI.identifier

mapper.insert:
INSERT INTO XBOLTADM.TB_ZZSAP_USER
(	
	ACCOUNT ,NAME ,PASSWORD ,GROUP_KEY ,GROUP_NAME ,SAUPJANG_KEY ,SAUPJANG_NAME ,DP_GROUP_KEY ,USERPOSITION ,TITLE ,EMAIL ,TELEPHONE,FAX
	,MOBILEPHONE ,OFFICEPHONE ,FLAGADDITIONALJOB ,ADDITIONALGROUPKEY ,USERCODE ,ACCESSGRADE ,JOBTITLE ,UPDATEDATE ,TITLECODE ,POSITIONCODE
	,STATUS_CODE ,ENTER_CD ,BASE3_YMD ,DISPATCHED_YMD ,RET_YMD ,SEX_TYPE ,PAY_GROUP_NM ,EMP_YMD ,RESIDENTS_BIGINT1 ,RESIDENTS_BIGINT2 ,COST_CD
	,CHK_ID ,CHK_DATE ,CALL_TITLE ,EMP_FUNCTION ,APPOINT_DATE ,FIX_DATE ,ENTERED_BY ,ATTR01 ,ATTR02 ,ATTR03 ,NAME_EN 			
) VALUES(
	#{ACCOUNT} ,#{NAME} ,#{PASSWORD} ,#{GROUP_KEY} ,#{GROUP_NAME} ,#{SAUPJANG_KEY} ,#{SAUPJANG_NAME} ,#{DP_GROUP_KEY} ,#{USERPOSITION} ,#{TITLE}
	,#{EMAIL} ,#{TELEPHONE} ,#{FAX} ,#{MOBILEPHONE} ,#{OFFICEPHONE} ,#{FLAGADDITIONALJOB} ,#{ADDITIONALGROUPKEY} ,#{USERCODE} ,#{ACCESSGRADE} ,#{JOBTITLE}
	,#{UPDATEDATE} ,#{TITLECODE} ,#{POSITIONCODE} ,#{STATUS_CODE} ,#{ENTER_CD} ,#{BASE3_YMD} ,#{DISPATCHED_YMD} ,#{RET_YMD} ,#{SEX_TYPE} ,#{PAY_GROUP_NM} 
	,#{EMP_YMD} ,#{RESIDENTS_BIGINT1},#{RESIDENTS_BIGINT2} ,#{COST_CD} ,#{CHK_ID} ,#{CHK_DATE} ,#{CALL_TITLE} ,#{EMP_FUNCTION} ,#{APPOINT_DATE} ,#{FIX_DATE} 
	,#{ENTERED_BY} ,#{ATTR01} ,#{ATTR02} ,#{ATTR03} ,#{NAME_EN}
)

INSERT INTO XBOLTADM.TB_ZZSAP_GROUP
(
	GROUP_KEY ,PARENTGROUP_KEY ,GROUP_NAME ,UPDATEDATE ,SAUPJANG_KEY ,SAUPJANG_NAME ,REPORT_NAME ,ATTR01 ,ATTR02 ,ATTR03
) VALUES
(
	#{GROUP_KEY} ,#{PARENTGROUP_KEY} ,#{GROUP_NAME} ,#{UPDATEDATE} ,#{SAUPJANG_KEY} ,#{SAUPJANG_NAME} ,#{REPORT_NAME} ,#{ATTR01} ,#{ATTR02} ,#{ATTR03}
)

mapper.select:
SELECT ZCL.DAY_ID
,'Total' AS REGION ,ISNULL(SUM(ZCL.CON_COUNT),0) AS 'CON_COUNT'
,ZCL.REGION ,ISNULL(ZCL.CON_COUNT,0) AS 'CON_COUNT'
FROM XBOLTADM.ZMD_CON_LOG ZCL WHERE ZCL.DAY_ID = #{dayId} AND ZCL.DAY_TYPE = 'DAY' AND ZCL.ITEMCODE = #{itemCode}
AND ZCL.REGION = #{region}
AND CONVERT(char(8),ZCL.DAY_ID, 112) BETWEEN #{startDt} AND #{endDt}
GROUP BY ZCL.DAY_ID

		SELECT ITEMCODE, SUM(CON_COUNT)
  		FROM XBOLTADM.ZMD_CON_LOG
  		WHERE
  			DAY_TYPE = 'DAY' 
			
				AND DAY_ID = #{dayId}
			    
  			
				
					AND REGION = #{region}
				
	  			
	  				AND REGION IS NULL
	  			
  			
  			
	  			
	  			AND ITEMTYPECODE = 'OJ00001'  AND ITEMCODE IS NOT NULL
	  			
	  			
	  			AND ITEMTYPECODE = #{itemTypeCode}
	  			
  			
  		ORDER BY DAY_ID DESC, REGION DESC, ITEMTYPECODE


SELECT TIA2.ItemID
  FROM XBOLTADM.TB_ITEM TI
  LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA 
       ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00000' AND TIA.LanguageID = #{languageID}
  LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 
       ON TIA.PlainText = TIA2.PlainText AND TIA2.AttrTypeCode = 'AT00054' AND TIA.LanguageID = #{languageID}
 WHERE TI.ItemID = #{itemID}

SELECT Row_Number()OVER(ORDER BY ZIP.Subject) as RNUM, ZIP.Subject, TATL.Value AS Type, ZIP.ProjectNo, ZIP.Nation, ZIP.RefUrl AS URL, ZIP.ReferenceGuid AS Parameter FROM XBOLTADM.Z_IF_PBPS ZIP LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL ON ZIP.RefTypeCd = TATL.LovCode AND TATL.AttrTypeCode = 'AT00037' AND TATL.languageID = #{languageID} WHERE ZIP.DetailJobCd = #{identifier} AND ZIP.CategoryCd = #{categoryCode}
AND ZIP.RefTypeCd NOT IN ('B0030001','B0030004','B0030012','B0080002')
AND ZIP.RefTypeCd = #{refTypeCode}
ORDER BY ZIP.Subject


 SELECT TI.ItemID
  FROM XBOLTADM.TB_ITEM TI
  LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA 
       ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00054' AND TIA.LanguageID = #{languageID}
  LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2
       ON TIA.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00037' AND TIA.LanguageID = #{languageID}
 WHERE TIA.PlainText = #{identifier} AND TIA2.PlainText = #{plainText}

mapper.delete:
DELETE XBOLTADM.TB_ITEM_ATTR WHERE ItemID = #{itemID}

DELETE XBOLTADM.TB_ELEMENT WHERE ObjectID = #{itemID}

DELETE XBOLTADM.TB_ITEM WHERE ItemID = #{itemID}

mapper.select:
SELECT Row_Number()OVER(ORDER BY A.ItemID) as RNUM, 0 as CHK, A.PlainText AS Name, (XBOLTADM.fn_GetDepartmentItemPath(A.JobItemID,#{languageID})) AS Path, A.ItemID CNItemID, B.ToItemID AS JobItemID FROM ( Select TI.ItemID, TOTI.ItemID as JobItemID, TIA.PlainText From XBOLTADM.tb_Item TI LEFT OUTER JOIN XBOLTADM.tb_Item TOTI ON TOTI.ItemId = TI.ToItemID LEFT OUTER JOIN XBOLTADM.tb_Item_ATTR TIA ON TIA.ItemId = TI.ToItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Where TI.ItemTypeCode = 'CN00102' And TI.FromITemID = #{itemID} And TI.Deleted != 1 )A Inner JOIN (SELECT TI4.ToItemID, TI4.ItemID FROM XBOLTADM.tb_item TI LEFT OUTER JOIN XBOLTADM.TB_ITEM TI2 ON TI2.FromItemID = TI.ItemID AND TI2.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TB_ITEM TI3 ON TI3.FromItemID = TI2.ToItemID AND TI3.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TB_ITEM TI4 ON TI4.FromItemID = TI3.ToItemID AND TI4.CategoryCode = 'ST1'
TI.itemid IN (Select ItemID From XBOLTADM.TB_MY_ITEM Where MemberID = #{memberID})
)B ON A.JobItemID = B.ToItemID ORDER BY A.ItemID

mapper.update:
    
	MERGE INTO XBOLTADM.TB_ITEM_ATTR  AS A
		USING (select 'X' as DUAL) AS B ON A.ItemID = #{itemID} AND A.AttrTypeCode = 'AT00005' AND A.LanguageID = #{languageID}
		WHEN MATCHED THEN
			UPDATE SET LovCode = #{lovCode}
		WHEN NOT MATCHED THEN
		INSERT (
					LanguageID
				, ItemID
				, AttrTypeCode
				, LovCode
				, ItemTypeCode
				, ClassCode
				, LastUpdated
		)
		VALUES (
					#{languageID}
				, #{itemID}
				, 'AT00005'
				, #{lovCode}
				, (Select ItemTypeCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{itemID})
				, (Select ClassCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{itemID})
				, GETDATE()
		);

mapper.select:
SELECT MemberID
FROM XBOLTADM.TB_MEMBER
where EmployeeNum = #{employeeNum}

mapper.insert:
MERGE INTO XBOLTADM.TB_PJT_MEMBER_REL  AS A
USING (select 'X' as DUAL) AS B ON A.MemberID = #{memberID} AND A.ProjectID = #{ProjectID}
WHEN NOT MATCHED THEN
INSERT (ProjectID, MemberID, Authority, AssignedDate)
VALUES(
	#{ProjectID}
	,#{memberID}
	,(SELECT Authority FROM XBOLTADM.TB_MEMBER WHERE MemberID = #{memberID})
	,getDate()
);

mapper.select:
Select Row_Number()OVER(ORDER BY T1.L1Code, T1.Code, T1.Path) as RNUM, T1.* From ( SELECT STR.FromItemID AS ParentID, STR.ToItemID AS ItemID, ISNULL(L1ID.Identifier, ITM.Identifier) AS L1Code, ISNULL(XBOLTADM.fn_GetMyAbsPathForList( ITM.ItemID ,#{languageID} ),'') AS Path, ITM.Identifier AS Code, CLS.Name AS Level , ATRNM.PlainText AS Name, ATRDESC.PlainText AS Description, ATRFREQ.PlainText As Frequency, ATRINPUT.PlainText As Input, ATROUTPUT.PlainText As Output, ATRLOV.Value AS SystemType, ATRSYS.PlainText As System, ATRTCODE.PlainText As TCODE, Author.EmployeeNum AS EditorEMPNum, Author.Name AS EditorNM, ITM.Status AS StatusCD, ITM.CreationTime, CONVERT(CHAR(10),CONVERT(datetime,ITM.LastUpdated ),21) as LastUpdated, Author.Name As AuthorName, TMTXT.Name As AuthorTeamName
FROM XBOLTADM.TB_ITEM AS STR LEFT OUTER JOIN XBOLTADM.TB_ITEM AS ITM ON ITM.ItemID = STR.ToItemID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY AS CLS ON CLS.TypeCode = ITM.ClassCode AND CLS.LanguageID = #{languageID} AND CLS.Category = 'CLS' Inner Join XBOLTADM.TW_PROCESS AS PRSUM ON PRSUM.ItemID = ITM.ItemID Inner Join XBOLTADM.TB_ITEM AS L1ID ON L1ID.ItemID = PRSUM.L1ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRNM ON ATRNM.ItemID = ITM.ItemID AND ATRNM.LanguageID = #{languageID} AND ATRNM.AttrTypeCode = 'AT00001' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRDESC ON ATRDESC.ItemID = ITM.ItemID AND ATRDESC.LanguageID = #{languageID} AND ATRDESC.AttrTypeCode = 'AT00003' LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRFREQ ON ATRFREQ.ItemID = ITM.ItemID AND ATRFREQ.LanguageID = #{languageID} AND ATRFREQ.AttrTypeCode = 'AT00009'LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRINPUT ON ATRINPUT.ItemID = ITM.ItemID AND ATRINPUT.LanguageID = #{languageID} AND ATRINPUT.AttrTypeCode = 'AT00015'LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATROUTPUT ON ATROUTPUT.ItemID = ITM.ItemID AND ATROUTPUT.LanguageID = #{languageID} AND ATROUTPUT.AttrTypeCode = 'AT00016'LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRSYS ON ATRSYS.ItemID = ITM.ItemID AND ATRSYS.LanguageID = #{languageID} AND ATRSYS.AttrTypeCode = 'AT00013'LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRSYSTYPE ON ATRSYSTYPE.ItemID = ITM.ItemID AND ATRSYSTYPE.LanguageID = #{languageID} AND ATRSYSTYPE.AttrTypeCode = 'AT00037' LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV AS ATRLOV ON ATRLOV.LovCode = ATRSYSTYPE.LovCode AND ATRLOV.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS ATRTCODE ON ATRTCODE.ItemID = ITM.ItemID AND ATRTCODE.LanguageID = #{languageID} AND ATRTCODE.AttrTypeCode = 'AT00014'LEFT OUTER JOIN XBOLTADM.TB_MEMBER AS AUTHOR ON AUTHOR.MemberID = ITM.AuthorID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMTXT ON TMTXT.TeamID = AUTHOR.TeamID And TMTXT.LanguageID = #{languageID}
Where STR.CategoryCode = 'ST1' And ITM.ItemTypeCode = 'OJ00001' AND ITM.ClassCode Not In ('CL01007', 'CL01008') And ITM.Deleted != 1 ) T1 Order by RNUM


 SELECT TI.ItemID
  FROM XBOLTADM.TB_ITEM TI
  LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA 
       ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00054' AND TIA.LanguageID = #{languageID}
  LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2
       ON TIA.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00037' AND TIA.LanguageID = #{languageID}
 WHERE TIA.PlainText = #{identifier} AND TIA2.PlainText = #{plainText}

SELECT DISTINCT T1.L1ItemID AS CODE , TIA.PlainText AS NAME FROM XBOLTADM.TW_PROCESS T1, XBOLTADM.TB_ITEM T3 Left Join XBOLTADM.TB_ITEM_ATTR TIA ON T3.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' and TIA.LanguageID = #{languageID} WHERE T1.L1ItemID = T3.ItemID AND T3.Identifier is not null AND T3.Identifier != ''
AND T1.L1ItemID = #{haederL2}
order by T1.L1ItemID

		SELECT
			Sum(TCL.CON_COUNT) AS CNT,
			case when HEADER_L1 = 'MemberCount' then HEADER_L1 else TCL.HEADER_L2 end AS L1ItemID,
			TI.Identifier
		FROM XBOLTADM.TW_CON_LOG TCL LEFT OUTER JOIN XBOLTADM.TB_ITEM TI ON TCL.HEADER_L2 = TI.itemID
		
			
			AND CONVERT(VARCHAR, DAY_ID, 111) = #{Date}
			
			
			AND CONVERT(VARCHAR, DAY_ID , 111) BETWEEN #{startDate} AND #{endDate}
						
			
			AND TCL.TEAMID = #{teamID}
			
			
			AND TCL.COMPANYID = #{companyID}
			
			
			AND DAY_TYPE = #{dayType}
			
				
  			AND (HEADER_L2 = #{haederL2} or HEADER_L1 = 'MemberCount')
  			
			
		
		Group by HEADER_L2, HEADER_L1, TI.Identifier
		Order by TI.Identifier

select distinct TCL.TEAMID AS CODE, TT.Name + '(' + ISNULL(TT.TeamCode,'N/A') + ')' AS NAME 
FROM XBOLTADM.TW_CON_LOG TCL LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT ON TCL.TEAMID = TT.TeamID 
WHERE TCL.TEAMID != ''
and TT.LanguageID = #{languageID}

	AND TCL.TEAMID = #{teamID}


	AND TCL.COMPANYID = #{companyID}

Order By NAME

SELECT 
	Distinct TCL.COMPANYID AS CODE, TXT.Name AS NAME
FROM XBOLTADM.TW_CON_LOG TCL Left Join XBOLTADM.TB_TEAM TT ON TCL.COMPANYID = TT.TeamID
		Left Join XBOLTADM.TB_TEAM_TXT TXT ON TXT.TEAMID = TT.TeamID
WHERE  TXT.LanguageID = #{languageID}
	AND TT.TeamType = #{teamType}

		SELECT	TI.itemID AS CODE
				,TIA.PlainText AS NAME
		From XBOLTADM.TB_ITEM TI Left Join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.LanguageID = #{languageID}
		WHERE TIA.AttrTypeCode = 'AT00001' and TI.ItemTypeCode = 'OJ00007' and TI.ClassCode = 'CL07001'
			
  			AND TI.itemID = #{haederL2}

Select Row_Number()OVER(ORDER BY substring(ZPS.Identifier, 2,1) ,ZPS.Identifier ) As RNUM, substring(ZPS.Identifier, 2,1) AS L1Code, TIC.Level AS Level, ZPS.Identifier AS ProcessID, REPLACE(ProcNM.PlainText, CHAR(11), '') AS ProcNM, REPLACE(L1NAME.PlainText, CHAR(11), '') AS L1Name, REPLACE(L2NAME.PlainText, CHAR(11), '') AS L2Name, REPLACE(L3NAME.PlainText, CHAR(11), '') AS L3Name, REPLACE(L4NAME.PlainText, CHAR(11), '') AS L4Name, ZPS.* FROM [XBOLTADM].[ZHMBS_PROC_SUM] ZPS Left Join XBOLTADM.TB_ITEM_ATTR ProcNM ON ProcNM.ItemID = ZPS.ItemID and ProcNM.LanguageID =#{languageID} and ProcNM.AttrTypeCode = 'AT00001' Left Join XBOLTADM.TB_ITEM_ATTR L1NAME ON L1NAME.ItemID = ZPS.L1ItemID and L1NAME.LanguageID =#{languageID} and L1NAME.AttrTypeCode = 'AT00001' Left Join XBOLTADM.TB_ITEM_ATTR L2NAME ON L2NAME.ItemID = ZPS.L2ItemID and L2NAME.LanguageID =#{languageID} and L2NAME.AttrTypeCode = 'AT00001' Left Join XBOLTADM.TB_ITEM_ATTR L3NAME ON L3NAME.ItemID = ZPS.L3ItemID and L3NAME.LanguageID =#{languageID} and L3NAME.AttrTypeCode = 'AT00001' Left Join XBOLTADM.TB_ITEM_ATTR L4NAME ON L4NAME.ItemID = ZPS.L4ItemID and L4NAME.LanguageID =#{languageID} and L4NAME.AttrTypeCode = 'AT00001' LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TIC ON ZPS.ItemClassCode = TIC.ItemClassCode
ZPS.ItemTypeCode = #{itemTypeCode}
AND ZPS.DimTypeID = #{dimTypeID}
ORDER BY L1Code ,ZPS.Identifier

SELECT DISTINCT Row_Number()OVER(ORDER BY TI.Identifier, TI.ClassCode) as RNUM , TI.ItemID , ISNULL(TIA.PlainText,'') AS ItemName , TD.Name as ClassName , TI.ClassCode , TI.Identifier , TITO.SortNum , TITO.CategoryCode , TI.Status As Status , TSD.Name As StatusName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , XBOLTADM.fn_GetMyAbsPathForList(TI.ItemID, #{languageID}) AS getPath , ISNULL(TMT.Name, '') AS TeamName , ISNULL(TOT.Name,'') AS OwnerTeamName , ISNULL(TM.Name,'') AS Name , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated
, TIA4.PlainText AS guideline , TATL5.Value AS applicationType , TIA6.PlainText AS modualAPP , TIA7.PlainText AS fioriID , TIA8.PlainText AS tCode , TIA9.PlainText AS chkPoint FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM TITO ON TITO.ToITemID = TI.ItemID And TITO.CategoryCode = 'ST1' And TITO.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 on TI.ItemID = TIA4.ItemID AND TIA4.AttrTypeCode = 'AT00008' AND TIA4.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 on TI.ItemID = TIA5.ItemID AND TIA5.AttrTypeCode = 'AT00037' AND TIA5.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL5 on TIA5.AttrTypeCode = TATL5.AttrTypeCode AND TIA5.LovCode = TATL5.LovCode AND TIA5.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA6 on TI.ItemID = TIA6.ItemID AND TIA6.AttrTypeCode = 'AT00013' AND TIA6.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA7 on TI.ItemID = TIA7.ItemID AND TIA7.AttrTypeCode = 'AT00039' AND TIA7.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 on TI.ItemID = TIA8.ItemID AND TIA8.AttrTypeCode = 'AT00014' AND TIA8.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA9 on TI.ItemID = TIA9.ItemID AND TIA9.AttrTypeCode = 'AT00053' AND TIA9.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TIC ON TIC.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode
LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT ON TMT.LanguageID = #{languageID} AND TMT.TeamID = TI.CompanyID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TOT.LanguageID = #{languageID} AND TOT.TeamID = TI.OwnerTeamID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD ON TSD.LanguageID = #{languageID} AND TSD.TypeCode = TI.Status AND TSD.Category = 'ITMSTS' WHERE TI.Deleted != 1 AND TI.ItemID IN (SELECT ToItemID FROM XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'ST1') Order by TITO.SortNum ASC

SELECT TI.ItemID , TIA1.PlainText AS ItemName , CASE WHEN TI.CategoryCode = 'REF' THEN ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TIA2.ItemID , #{languageID} ),'')+'/'+ TIA2.PlainText WHEN TI.CategoryCode IN('MCN', 'CN', 'CN1') THEN ISNULL(TIAF.PlainText,'') + ' --> ' + ISNULL(TIAT.PlainText,'') ELSE ISNULL(XBOLTADM.fn_GetMyAbsPathForList( #{s_itemID} ,#{languageID} ),'') END AS Path , TD.Name as ClassName , TDI.Name as ItemTypeName , TT.Name as TeamName , TOT.Name as OwnerTeamName , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End AS Name , CONVERT(VARCHAR, TI.CreationTime, 111) AS CreateDT , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , TCS.Version , TI.Identifier , TI.AuthorID AS AuthorID , TI.LockOwner AS LockOwner , TI.OwnerTeamID , TIA3.PlainText AS Description , TI.ClassCode AS ClassCode , TI.Level AS Level , Case When TI.Deleted = 1 Then TD2.Name + '(Deleted)' Else TD2.Name END As StatusName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , (Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} And CategoryCode = 'ST1') AS FromItemID , TPT.Name AS ProjectName , TPT2.Name As RefPjtName , TI.ProjectID AS ProjectID , TI.CurChangeSet , TI.ReleaseNo , TI.Status , TI.Blocked , ISNULL(TITF.Icon, 'img_job.png') FromItemTypeImg , ISNULL(TITT.Icon, 'img_job.png') ToItemTypeImg , LTRIM(RTRIM(TI.CategoryCode)) AS CategoryCode , ISNULL(TIAF.PlainText,'') AS FromItemName , ISNULL(TIAT.PlainText,'') AS ToItemName , TCL.CheckOutOption , TCS.CheckInOption , TCS.Reason , TCS.Description AS ChangeSetDec , ISNULL(CONVERT(char(10), TCS.CompletionDT, 111),'-') as CompletionDT , TCL.SubscrOption , TCL.ChangeMgt , ISNULL(TM.Name,'') AS AuthorName , TI.ItemTypeCode , TCS.WFInstanceID , Convert(nvarchar(20),ISNULL(TCS.ValidFrom,TI.LastUpdated), 111) AS ValidFrom , STUFF(( SELECT '/' + convert(nvarchar, B.NAME) FROM XBOLTADM.TB_ITEM_DIM A inner join XBOLTADM.TB_DIM_VALUE_TXT B ON A.DimTypeID = B.DimTypeID and A.DimValueID = B.DimValueID and B.LanguageID = #{languageID} WHERE A.ItemID = TI.ItemID AND A.DimTypeID = '100003' FOR XML PATH('') ), 1, 1, '') AS DimValueIDs
FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 on TI.ItemID = TIA1.ItemID AND TIA1.AttrTypeCode = 'AT00001' AND TIA1.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 on TI.RefItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00001' AND TIA2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 on TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'AT00003' AND TIA3.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD2 on TI.Status = TD2.TypeCode AND TD2.Category = 'ITMSTS' AND TD2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_PROJECT TP ON TP.ProjectID = TI.ProjectID LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT TPT On TPT.ProjectID = TI.ProjectID And TPT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT TPT2 On TPT2.ProjectID = TP.RefPjtID And TPT2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAF ON TIAF.ItemID IN(Select FromItemID From XBOLTADM.tb_Item where ItemID = #{s_itemID}) And TIAF.AttrTypeCode = 'AT00001' And TIAF.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAT ON TIAT.ItemID IN(Select ToItemID From XBOLTADM.tb_Item where ItemID = #{s_itemID}) And TIAT.AttrTypeCode = 'AT00001' And TIAT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TITF ON TITF.ItemTypeCode IN(Select ItemTypeCode From XBOLTADM.TB_ITEM Where ItemID = TI.FromItemID) LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TITT ON TITT.ItemTypeCode IN(Select ItemTypeCode From XBOLTADM.TB_ITEM Where ItemID = TI.ToItemID) LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCL ON TCL.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TCS.ChangeSetID = TI.CurChangeSet LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDI on TI.ItemTypeCode = TDI.TypeCode AND TDI.LanguageID = #{languageID}
WHERE TI.ItemID = #{s_itemID}

Select Row_Number()OVER(ORDER BY L1ID.Identifier,ITM.Identifier) as RNUM, ISNULL(L1ID.Identifier, ITM.Identifier) AS L1Code, ISNULL(XBOLTADM.fn_GetMyAbsPathForList( ITM.ItemID ,#{languageID} ),'') AS Path, ITM.Identifier AS ID, TIA.PlainText AS ItemName, TIM.Name AS ItemAuthor, TMT.Name AS ModelName, TD2.Name AS MTCategory, TD.Name AS ModelStatus, CONVERT(CHAR(10),CONVERT(datetime,TM.LastUpdated ),21) as LastUpdated, TMM.Name AS MDLastUser From XBOLTADM.TB_ITEM AS STR LEFT OUTER JOIN XBOLTADM.TB_ITEM AS ITM ON ITM.ItemID = STR.ToItemID LEFT OUTER JOIN XBOLTADM.TW_PROCESS AS PRSUM ON PRSUM.ItemID = ITM.ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM AS L1ID ON L1ID.ItemID = PRSUM.L1ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON ITM.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' LEFT OUTER JOIN XBOLTADM.TB_MODEL TM ON ITM.ItemID = TM.ItemID LEFT OUTER JOIN XBOLTADM.TB_MODEL_TXT TMT ON TM.ModelID = TMT.ModelID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD ON TM.Status = TD.TypeCode AND TD.Category = 'MDLSTS' AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD2 ON TM.MTCategory = TD2.TypeCode AND TD2.Category = 'MC' AND TD2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TIM ON ITM.AuthorID = TIM.MemberID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TMM ON TM.LastUser = TMM.MemberID Where STR.CategoryCode = 'ST1' And ITM.ItemTypeCode = 'OJ00001' And ITM.ClassCode = 'CL01005' And ITM.Deleted != 1
And L1ID.Identifier = #{L1List}
Order By RNUM, L1Code, ID

WITH TreeTable AS( Select T1.* From ( SELECT STR.FromItemID AS ParentID, ISNULL(L1ID.Identifier, ITM.Identifier) AS L1Code, STR.ToItemID AS ItemID,
ITM.Identifier AS Code, CLS.Name AS Level , ATRNM.PlainText AS Name, CN00107.Identifier AS RuleSet, CN00108.Identifier AS KPI, CN00109.Identifier AS Control, CN00201.Identifier AS Role, CN00104.Identifier AS System, TDVT.Name AS dimension, Author.Name AS EditorNM, CONVERT(CHAR(10),CONVERT(datetime,ITM.LastUpdated ),21) as LastUpdated FROM XBOLTADM.TB_ITEM AS STR LEFT OUTER JOIN XBOLTADM.TB_ITEM AS ITM ON ITM.ItemID = STR.ToItemID LEFT OUTER JOIN XBOLTADM.TW_PROCESS AS PRSUM ON PRSUM.ItemID = ITM.ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM AS L1ID ON L1ID.ItemID = PRSUM.L1ItemID LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY AS CLS ON CLS.TypeCode = ITM.ClassCode AND CLS.LanguageID = #{languageID} AND CLS.Category = 'CLS' Inner Join XBOLTADM.TB_ITEM_ATTR AS ATRNM ON ATRNM.ItemID = ITM.ItemID AND ATRNM.LanguageID = #{languageID} AND ATRNM.AttrTypeCode = 'AT00001' LEFT OUTER JOIN XBOLTADM.TB_MEMBER AS AUTHOR ON AUTHOR.MemberID = ITM.AuthorID LEFT OUTER JOIN XBOLTADM.TB_ITEM TI1 ON TI1.FromItemID = ITM.ItemID AND TI1.ItemTypeCode = 'CN00107' And TI1.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_ITEM CN00107 ON CN00107.ItemID = TI1.ToItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM TI2 ON TI2.FromItemID = ITM.ItemID AND TI2.ItemTypeCode = 'CN00108' And TI2.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_ITEM CN00108 ON CN00108.ItemID = TI2.ToItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM TI3 ON TI3.FromItemID = ITM.ItemID AND TI3.ItemTypeCode = 'CN00109' And TI3.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_ITEM CN00109 ON CN00109.ItemID = TI3.ToItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM TI4 ON TI4.ToItemID = ITM.ItemID AND TI4.ItemTypeCode = 'CN00201' And TI4.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_ITEM CN00201 ON CN00201.ItemID = TI4.FromItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM TI5 ON TI5.FromItemID = ITM.ItemID AND TI5.ItemTypeCode = 'CN00104' And TI5.Deleted != 1 LEFT OUTER JOIN XBOLTADM.TB_ITEM CN00104 ON CN00104.ItemID = TI5.ToItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_DIM TID ON TID.ItemID = ITM.ItemID LEFT OUTER JOIN XBOLTADM.TB_DIM_VALUE_TXT TDVT ON TDVT.DimValueID = TID.DimValueID AND TDVT.LanguageID = #{languageID} Where STR.CategoryCode = 'ST1' And ITM.ItemTypeCode = 'OJ00001' AND ITM.ClassCode Not In ('CL01000','CL01007', 'CL01008') And ITM.Deleted != 1 ) T1 )
select Row_Number()OVER(ORDER BY B.Code) as RNUM, B.* From ( Select distinct A.ItemID
, A.L1Code , A.Code , A.Level , A.Name , STUFF((select distinct '/' + RuleSet From TreeTable where TreeTable.ItemID = A.ItemID for xml path('')),1,1,'') AS RuleSet , STUFF((select distinct '/' + KPI From TreeTable where TreeTable.ItemID = A.ItemID for xml path('')),1,1,'') AS KPI , STUFF((select distinct '/' + Control From TreeTable where TreeTable.ItemID = A.ItemID for xml path('')),1,1,'') AS Control , STUFF((select distinct '/' + Role From TreeTable where TreeTable.ItemID = A.ItemID for xml path('')),1,1,'') AS Role , STUFF((select distinct '/' + System From TreeTable where TreeTable.ItemID = A.ItemID for xml path('')),1,1,'') AS System , STUFF((select distinct '/' + dimension From TreeTable where TreeTable.ItemID = A.ItemID for xml path('')),1,1,'') AS Dimension , (select count(*) From XBOLTADM.TB_FILE TF where A.ItemID = TF.DocumentID AND TF.DocCategory = 'ITM') AS FileCNT , A.EditorNM , A.LastUpdated From TreeTable AS A Where 1=1
and A.L1Code = #{L1List}
) B Order by RNUM

  		
  		SELECT LovCode
		FROM XBOLTADM.TB_ITEM_ATTR IA 
	    LEFT OUTER JOIN	XBOLTADM.TB_LANGUAGE DefLang
			 on IA.LanguageID  = DefLang.LanguageID and DefLang.IsDefault = 1
		WHERE IA.ItemID = #{itemID}
		And IA.AttrTypeCode = #{attrTypeCode}

  		
  		SELECT ExtCode
		FROM XBOLTADM.TB_LANGUAGE
		WHERE LanguageID = #{languageID}

  		
 		SELECT top 1 A.TOP_MENU_ID, A.FUNCTION_ID, B.APPLICATION_ID, B.RESPONSIBILITY_ID, A.function_ID
 		  FROM XBOLTADM.ZMD_ERP_FUNCTION A 
	 	  INNER JOIN XBOLTADM.ZMD_ERP_ROLL B 
	 			ON A.TOP_MENU_ID = B.MENU_ID 
	 			AND A.function_ID = #{functionID}
	 			AND B.USER_NAME = #{empNum}

SELECT Row_Number()OVER(ORDER BY P.Identifier,K.Identifier) as RNUM, P.ItemID AS ProcItemID ,P.Identifier AS ProcCode ,PNM.PlainText AS ProcName ,K.ItemID AS KpiItemID ,K.Identifier AS KpiCode ,KNM.PlainText AS KpiName ,TT.TeamID ,TTT.Name AS TeamName , Convert(nvarchar(20),A.LastUpdated, 111) AS LastUpdated ,A.TargetValue ,A.Remark ,A.Year ,A.Month1 ,A.Month2 ,A.Month3 ,A.Month4 ,A.Month5 ,A.Month6 ,A.Month7 ,A.Month8 ,A.Month9 ,A.Month10 ,A.Month11 ,A.Month12 FROM XBOLTADM.Z_KPI_VALUE A INNER JOIN XBOLTADM.TB_ITEM P ON A.ObjectID =P.ItemID INNER JOIN XBOLTADM.TB_ITEM_ATTR PNM ON P.ItemID = PNM.ItemID AND PNM.AttrTypeCode = 'AT00001' AND PNM.LanguageID = #{languageID} INNER JOIN XBOLTADM.TB_ITEM K ON A.KpiItemID = K.ItemID INNER JOIN XBOLTADM.TB_ITEM_ATTR KNM ON K.ItemID = KNM.ItemID AND KNM.AttrTypeCode = 'AT00001' AND KNM.LanguageID = #{languageID} INNER JOIN XBOLTADM.TB_TEAM TT ON A.TeamID = TT.TeamID AND TT.Deleted = 0 INNER JOIN XBOLTADM.TB_TEAM_TXT TTT ON TT.TeamID = TTT.TeamID AND TTT.LanguageID = #{languageID}
(A.kpiItemID = #{kpiItemID} OR A.kpiItemID IN (SELECT ToItemID FROM XBOLTADM.TB_ITEM WHERE FromItemID = #{kpiItemID} AND CategoryCode = 'ST1')) AND A.Year = #{kpiYear} AND P.ItemID = #{procID} AND K.ItemID = #{kpiID}
AND ( ISNULL(XBOLTADM.fn_GetMyAbsPathForOrg(TT.TeamID , #{languageID}), '') like '%' + (SELECT Name FROM XBOLTADM.TB_TEAM_TXT WHERE TeamID = #{teamID} AND LanguageID = #{languageID}) + '%' OR TTT.Name like '%'+CONVERT(varchar(255),(SELECT Name FROM XBOLTADM.TB_TEAM_TXT WHERE TeamID = #{teamID} AND LanguageID = #{languageID}))+'%' )
AND TTT.Name like '%'+CONVERT(varchar(255),#{teamName})+'%'
ORDER BY P.Identifier,K.Identifier

	
		
	SELECT  DISTINCT P.ItemID AS CODE
	      , PNM.PlainText AS NAME
		FROM XBOLTADM.Z_KPI_VALUE A
			INNER JOIN XBOLTADM.TB_ITEM P ON A.ObjectID = P.ItemID
			INNER JOIN XBOLTADM.TB_ITEM_ATTR PNM ON P.ItemID = PNM.ItemID AND PNM.AttrTypeCode = 'AT00001' AND PNM.LanguageID = #{languageID}
	
		WHERE
		       A.Year = #{kpiYear}
        	   
					AND A.KPIItemID = #{kpiItemID}
			    
	UNION ALL
	SELECT  DISTINCT P.ItemID AS CODE
	      , PNM.PlainText AS NAME		
      FROM XBOLTADM.TB_ITEM KCN
		   INNER JOIN XBOLTADM.Z_KPI_VALUE A ON KCN.ToItemID = A.KpiItemID AND KCN.CategoryCode = 'ST1'
		   INNER JOIN XBOLTADM.TB_ITEM P ON A.ObjectID = P.ItemID
		   INNER JOIN XBOLTADM.TB_ITEM_ATTR PNM ON P.ItemID = PNM.ItemID AND PNM.AttrTypeCode = 'AT00001' AND PNM.LanguageID = #{languageID}
	 WHERE 
	       A.Year = #{kpiYear}
       	   
				AND KCN.FromItemID = #{kpiItemID}
		    

		ORDER BY NAME

SELECT DISTINCT A.KPIItemID AS CODE , KNM.PlainText AS NAME FROM XBOLTADM.Z_KPI_VALUE A INNER JOIN XBOLTADM.TB_ITEM_ATTR KNM ON A.KPIItemID = KNM.ItemID AND KNM.AttrTypeCode = 'AT00001' AND KNM.LanguageID = #{languageID}
WHERE A.Year = #{kpiYear}
AND A.KPIItemID = #{kpiItemID}
UNION ALL SELECT DISTINCT KCN.ToItemID AS CODE , KNM.PlainText AS NAME FROM XBOLTADM.TB_ITEM KCN INNER JOIN XBOLTADM.Z_KPI_VALUE A ON KCN.ToItemID = A.KpiItemID INNER JOIN XBOLTADM.TB_ITEM_ATTR KNM ON KCN.ToItemID = KNM.ItemID AND KNM.AttrTypeCode = 'AT00001' AND KNM.LanguageID = #{languageID} WHERE A.Year = #{kpiYear}
AND KCN.FromItemID = #{kpiItemID} AND KCN.CategoryCode = 'ST1'
ORDER BY NAME

mapper.insert:
		INSERT INTO XBOLTADM.Z_KPI_VALUE
		   (ObjectID
           ,KpiItemID
           ,TeamID
           ,LastUpdated
           ,TargetValue
           ,Value
           ,Year
           ,Creator
           ,Remark   
           ,Month      )
     	VALUES
           (#{objID}
            ,#{kpiID}
            ,#{teamID}
            ,#{lastUpdated}
            ,#{TargetValue}
            ,#{Value}
            ,#{Year}
            ,#{memberID}
           ,#{Remark}   
           ,#{Month}     )

mapper.update:
	Update XBOLTADM.Z_KPI_VALUE Set 
		TargetValue = #{TargetValue}
		, Value = #{Value}
		, LastUpdated = GetDate()
		,Remark = #{Remark}
		, Year = #{Year}
	WHERE ObjectID = #{objID}
       AND KpiItemID = #{kpiID}
       AND TeamID = #{teamID}
       AND Year = #{YearOrg}
       AND Month = #{Month}

	Delete From XBOLTADM.Z_KPI_VALUE
	WHERE ObjectID = #{objID}
       AND KpiItemID = #{kpiID}
       AND TeamID = #{teamID}
       AND Year = #{year}

mapper.select:
	
	SELECT ISNULL(COUNT(*),'0') AS CNT
	  FROM XBOLTADM.Z_KPI_VALUE
	 WHERE ObjectID = #{objID}
       AND KpiItemID = #{kpiID}
       AND TeamID = #{teamID}
       AND Year IN (${Year})
       AND Month = #{Month}

SELECT Row_Number()OVER(ORDER BY P.Identifier,K.Identifier) as RNUM, P.ItemID AS ProcItemID ,P.Identifier AS ProcCode ,PNM.PlainText AS ProcName ,K.ItemID AS KpiItemID ,K.Identifier AS KpiCode ,KNM.PlainText AS KpiName ,TT.TeamID ,TTT.Name AS TeamName ,ISNULL(Convert(nvarchar(20),(SELECT Max(LastUpdated) FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year), 111),'') AS KpiLastUpdated ,ISNULL((SELECT Max(TargetValue) FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year),'') AS TargetValue ,ISNULL((SELECT Max(Remark) FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year),'') AS Remark ,A.Year ,A.Year AS YearOrg ,ISNULL(STUFF ((SELECT DISTINCT ',' + DimValueID FROM XBOLTADM.TB_ITEM_DIM TID LEFT OUTER JOIN XBOLTADM.Z_KPI_VALUE k ON k.ObjectID = TID.ItemID WHERE k.ObjectID = A.ObjectID and dimTypeId = '115053' FOR XML PATH('')) ,1,1,''),'') AS CompanyList ,ISNULL(A.Creator,'') AS RoleManagerID ,ISNULL(TM.Name,'') + CASE WHEN ISNULL(TM.NameEN,'') != '' THEN '(' + TM.NameEN + ')' ELSE '' END AS RoleManagerNM ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 1),'') AS Month1 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 2),'') AS Month2 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 3),'') AS Month3 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 4),'') AS Month4 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 5),'') AS Month5 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 6),'') AS Month6 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 7),'') AS Month7 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 8),'') AS Month8 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 9),'') AS Month9 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 10),'') AS Month10 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 11),'') AS Month11 ,ISNULL((SELECT Value FROM XBOLTADM.Z_KPI_VALUE WHERE ObjectID = A.ObjectID AND kpiItemID = A.kpiItemID AND TeamID = A.TeamID AND Year = A.Year AND Month = 12),'') AS Month12 ,ISNULL(TIA.PlainText,'') AS AT00009TEXT FROM (SELECT ObjectID,kpiItemID,TeamID,Year,Creator FROM XBOLTADM.Z_KPI_VALUE GROUP BY ObjectID,kpiItemID,TeamID,Year,Creator) A INNER JOIN XBOLTADM.TB_ITEM P ON A.ObjectID =P.ItemID INNER JOIN XBOLTADM.TB_ITEM_ATTR PNM ON P.ItemID = PNM.ItemID AND PNM.AttrTypeCode = 'AT00001' AND PNM.LanguageID = #{languageID} INNER JOIN XBOLTADM.TB_ITEM K ON A.KpiItemID = K.ItemID INNER JOIN XBOLTADM.TB_ITEM_ATTR KNM ON K.ItemID = KNM.ItemID AND KNM.AttrTypeCode = 'AT00001' AND KNM.LanguageID = #{languageID} INNER JOIN XBOLTADM.TB_TEAM TT ON A.TeamID = TT.TeamID AND TT.Deleted = 0 INNER JOIN XBOLTADM.TB_TEAM_TXT TTT ON TT.TeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = K.ItemID And TIA.AttrTypeCode = 'AT00009' And TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = A.Creator
AND A.Year = #{kpiYear} AND P.ItemID = #{procID} AND K.ItemID = #{kpiID}
AND ( A.kpiItemID IN (SELECT TIH.ItemID FROM XBOLTADM.TW_ITEM_HIER TIH WHERE (CASE WHEN #{kpiItemID} = TIH.L0ItemID THEN 1 WHEN #{kpiItemID} = TIH.L1ItemID THEN 1 WHEN #{kpiItemID} = TIH.L2ItemID THEN 1 WHEN #{kpiItemID} = TIH.L3ItemID THEN 1 WHEN #{kpiItemID} = TIH.L4ItemID THEN 1 WHEN #{kpiItemID} = TIH.L5ItemID THEN 1 WHEN #{kpiItemID} = TIH.L6ItemID THEN 1 ELSE 0 END) = 1 ) OR A.kpiItemID = #{kpiItemID})
AND ( A.ObjectID IN (SELECT TIH.ItemID FROM XBOLTADM.TW_ITEM_HIER TIH WHERE (CASE WHEN #{allItemID} = TIH.L0ItemID THEN 1 WHEN #{allItemID} = TIH.L1ItemID THEN 1 WHEN #{allItemID} = TIH.L2ItemID THEN 1 WHEN #{allItemID} = TIH.L3ItemID THEN 1 WHEN #{allItemID} = TIH.L4ItemID THEN 1 WHEN #{allItemID} = TIH.L5ItemID THEN 1 WHEN #{allItemID} = TIH.L6ItemID THEN 1 ELSE 0 END) = 1 ) OR A.ObjectID = #{allItemID})
AND ( ISNULL(XBOLTADM.fn_GetMyAbsPathForOrg(TT.TeamID , #{languageID}), '') like '%' + (SELECT Name FROM XBOLTADM.TB_TEAM_TXT WHERE TeamID = #{teamID} AND LanguageID = #{languageID}) + '%' OR TTT.Name like '%'+CONVERT(varchar(255),(SELECT Name FROM XBOLTADM.TB_TEAM_TXT WHERE TeamID = #{teamID} AND LanguageID = #{languageID}))+'%' )
AND TTT.Name like '%'+CONVERT(varchar(255),#{teamName})+'%'
AND A.Creator = #{authorID} AND A.TeamID = #{roleTeamID}
AND A.Year = #{year}
ORDER BY P.Identifier,K.Identifier, A.Year

Select distinct T.MemberID AS rctMemberID, T.Name AS rctMemberNM, T.TeamNM AS TeamNM From (
Select TT.ManagerID As MemberID, TTM.Name AS Name, TTX.Name AS TeamNM From XBOLTADM.TB_ITEM TI Inner Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID LEFT OUTER JOIN XBOLTADM.TB_TEAM TT ON TM.TeamID = TT.TeamID Inner Join XBOLTADM.TB_MEMBER TTM ON TTM.MemberID = TT.ManagerID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX ON TTX.TeamID = TT.TeamID AND TTX.LanguageID = #{languageID} Where TI.ItemID = #{itemID}
UNION
Select ISNULL(TTR.RoleManagerID, TT.RoleManagerID) As MemberID, ISNULL(TM.Name, TM1.Name) AS Name, ISNULL(TTX.Name, TTX1.Name) AS TeamNM
From XBOLTADM.TB_TEAM_ROLE TTR LEFT OUTER JOIN XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID Left Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TTR.RoleManagerID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX ON TTX.TeamID = TM.TeamID AND TTX.LanguageID = #{languageID} Inner Join XBOLTADM.TB_MEMBER TM1 ON TM1.MemberID = TT.RoleManagerID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX1 ON TTX1.TeamID = TM1.TeamID AND TTX1.LanguageID = #{languageID} WHERE (TTR.RoleManagerID is not null OR TT.RoleManagerID is not null) and TTR.ItemID = #{itemID} and TTR.Assigned in (1,2) and TTR.TeamRoleType != 'A'
UNION
select TM.MemberID As MemberID, TM.Name AS Name, TTX.Name AS TeamNM from XBOLTADM.TB_TEAM_ROLE TTR LEFT OUTER JOIN XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID Inner Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TT.ManagerID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX ON TTX.TeamID = TM.TeamID AND TTX.LanguageID = #{languageID} where TTR.ItemID = #{itemID} and TM.MemberID is not null and TTR.Assigned in (1,2) and TTR.TeamRoleType != 'A'
UNION
Select TMI.MemberID As MemberID, TM.Name AS Name, TTX.Name AS TeamNM
From XBOLTADM.TB_MY_ITEM TMI Inner Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TMI.MemberID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTX ON TTX.TeamID = TM.TeamID AND TTX.LanguageID = #{languageID}
Where TMI.ItemID = #{itemID} And AccessRight = 'R' And TMI.MemberID Not In (Select AuthorID from XBOLTADM.TB_ITEM where ItemID = #{itemID}) And TMI.AssignmentType != 'SUBSCR'
And TMI.AssignmentType = #{assignmentType}
) T

SELECT *
  FROM [XBOLTADM].[APRV_WG_INFO_VIEW]
 WHERE MemberID = #{userID}

SELECT *
  FROM [XBOLTADM].[APRV_GW_INFO_VIEW]
 WHERE TeamID = #{teamID}

WITH ITEMTREE AS( select ItemID, Identifier, ClassCode, ItemTypeCode , convert(bigint, 0) AS P_itemID, convert(nvarchar(100), '') AS P_Identifier from XBOLTADM.TB_ITEM WHERE ItemID = #{s_itemID} UNION ALL select C.ItemID, C.Identifier, C.ClassCode, C.ItemTypeCode, P.ItemID AS P_itemID, P.Identifier AS P_Identifier from ITEMTREE P inner join XBOLTADM.TB_ITEM ST ON P.ItemID = ST.FromItemID AND ST.CategoryCode = 'ST1' inner join XBOLTADM.TB_ITEM C ON C.ItemID = ST.ToItemID ) SELECT isnull(pivot_result.PT_OVER,0) AS PT_OVER , isnull(pivot_result.PT_UNDER,0) AS PT_UNDER FROM ( SELECT ProgressType, count(ProgressType) AS ProgressTypeCNT FROM( select A.* , TIA1.PlainText AS EffectiveDate , TIA2.PlainText AS TrackingProgress , CASE WHEN Convert(date,TIA1.PlainText) < DATEADD(DAY, -1, CONVERT(DATE, CONVERT(VARCHAR(6), GETDATE(), 112) + '01')) THEN 'PT_OVER' ELSE 'PT_UNDER' END AS ProgressType
from ITEMTREE A Left join XBOLTADM.TB_ITEM_ATTR TIA1 ON A.ItemID = TIA1.ItemID AND TIA1.AttrTypeCode = 'ZAT1040' AND TIA1.LanguageID = #{languageID} Left join XBOLTADM.TB_ITEM_ATTR TIA2 ON A.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'ZAT1011' AND TIA2.LanguageID = #{languageID}
INNER JOIN XBOLTADM.TB_ITEM_ATTR PTIA ON A.P_itemID = PTIA.ItemID AND PTIA.AttrTypeCode = 'AT00001' AND PTIA.LanguageID = #{languageID} WHERE A.ClassCode = 'CL13003' --GROUP BY PTIA.PlainText, TIA2.PlainText ) AAA Group by ProgressType ) AAAA PIVOT ( sum(AAAA.ProgressTypeCNT) FOR AAAA.ProgressType IN ([PT_OVER],[PT_UNDER]) ) AS pivot_result

SELECT VisitDate , SUM(VisitCNT1) AS VisitCNT1 , Convert(nvarchar, SUM(GRMemberCNT1)) AS GRMemberCNT1 , SUM(VisitCNT2) AS VisitCNT2 , Convert(nvarchar, SUM(GRMemberCNT2)) AS GRMemberCNT2 , SUM(VisitCNT3) AS VisitCNT3 , Convert(nvarchar, SUM(GRMemberCNT3)) AS GRMemberCNT3 , SUM(VisitCNT4) AS VisitCNT4 , Convert(nvarchar, SUM(GRMemberCNT4)) AS GRMemberCNT4 , SUM(VisitCNT5) AS VisitCNT5 , Convert(nvarchar, SUM(GRMemberCNT5)) AS GRMemberCNT5 , SUM(VisitCNT6) AS VisitCNT6 , Convert(nvarchar, SUM(GRMemberCNT6)) AS GRMemberCNT6 , SUM(VisitCNT7) AS VisitCNT7 , Convert(nvarchar, SUM(GRMemberCNT7)) AS GRMemberCNT7 , SUM(VisitCNT8) AS VisitCNT8 , Convert(nvarchar, SUM(GRMemberCNT8)) AS GRMemberCNT8 , (SUM(VisitCNT1) + SUM(VisitCNT2) + SUM(VisitCNT3) + SUM(VisitCNT4) + SUM(VisitCNT5) + SUM(VisitCNT6) + SUM(VisitCNT7) + SUM(VisitCNT8)) AS VisitCNT , Convert(nvarchar, (SUM(GRMemberCNT1) + SUM(GRMemberCNT2) + SUM(GRMemberCNT3) + SUM(GRMemberCNT4) + SUM(GRMemberCNT5) + SUM(GRMemberCNT6) + SUM(GRMemberCNT7) + SUM(GRMemberCNT8))) AS TotalGRMemberCNT FROM ( SELECT GR.VisitDate ,CASE WHEN TTT.TeamCode = 'K01193' THEN GR.VisitCNT ELSE 0 END VisitCNT1 ,CASE WHEN TTT.TeamCode = 'K00012' THEN GR.VisitCNT ELSE 0 END VisitCNT2 ,CASE WHEN TTT.TeamCode = 'K01024' THEN GR.VisitCNT ELSE 0 END VisitCNT3 ,CASE WHEN TTT.TeamCode = 'K01251' THEN GR.VisitCNT ELSE 0 END VisitCNT4 ,CASE WHEN TTT.TeamCode = 'K00015' THEN GR.VisitCNT ELSE 0 END VisitCNT5 ,CASE WHEN TTT.TeamCode = 'K00090' THEN GR.VisitCNT ELSE 0 END VisitCNT6 ,CASE WHEN TTT.TeamCode = 'K00513' THEN GR.VisitCNT ELSE 0 END VisitCNT7 ,CASE WHEN TTT.TeamCode = 'K00092' THEN GR.VisitCNT ELSE 0 END VisitCNT8
,CASE WHEN TTT.TeamCode = 'K01193' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT1 ,CASE WHEN TTT.TeamCode = 'K00012' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT2 ,CASE WHEN TTT.TeamCode = 'K01024' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT3 ,CASE WHEN TTT.TeamCode = 'K01251' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT4 ,CASE WHEN TTT.TeamCode = 'K00015' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT5 ,CASE WHEN TTT.TeamCode = 'K00090' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT6 ,CASE WHEN TTT.TeamCode = 'K00513' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT7 ,CASE WHEN TTT.TeamCode = 'K00092' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT8 FROM [XBOLTADM].[TW_GR_VISIT_LOG] GR LEFT JOIN XBOLTADM.TB_TEAM_TXT TTT ON TTT.TeamID = GR.GRTeam AND TTT.LanguageID = 1042 WHERE GR.DataType = 'DAY'
AND GR.VisitDate >= #{startDate}
AND GR.VisitDate <= #{endDate}
)AA GROUP BY VisitDate
union all
SELECT 'SUM/AVG' , BB.VisitCNT1 , case when GRMemberCNT1 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT1 AS float)) / (CAST(GRMemberCNT1 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT1 , BB.VisitCNT2 , case when GRMemberCNT2 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT2 AS float)) / (CAST(GRMemberCNT2 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT2 , BB.VisitCNT3 , case when GRMemberCNT3 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT3 AS float)) / (CAST(GRMemberCNT3 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT3 , BB.VisitCNT4 , case when GRMemberCNT4 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT4 AS float)) / (CAST(GRMemberCNT4 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT4 , BB.VisitCNT5 , case when GRMemberCNT5 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT5 AS float)) / (CAST(GRMemberCNT5 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT5 , BB.VisitCNT6 , case when GRMemberCNT6 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT6 AS float)) / (CAST(GRMemberCNT6 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT6 , BB.VisitCNT7 , case when GRMemberCNT7 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT7 AS float)) / (CAST(GRMemberCNT7 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT7 , BB.VisitCNT8 , case when GRMemberCNT8 > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT8 AS float)) / (CAST(GRMemberCNT8 AS float))) * 100,0)) else '0' end + '%' AS GRMemberCNT8 , BB.VisitCNT , case when TotalGRMemberCNT > 0 then convert(nvarchar, ROUND(((CAST(BB.VisitCNT AS float)) / (CAST(TotalGRMemberCNT AS float))) * 100,0)) else '0' end + '%' AS TotalGRMemberCNT FROM( SELECT SUM(VisitCNT1) AS VisitCNT1 , SUM(GRMemberCNT1) AS GRMemberCNT1 , SUM(VisitCNT2) AS VisitCNT2 , SUM(GRMemberCNT2) AS GRMemberCNT2 , SUM(VisitCNT3) AS VisitCNT3 , SUM(GRMemberCNT3) AS GRMemberCNT3 , SUM(VisitCNT4) AS VisitCNT4 , SUM(GRMemberCNT4) AS GRMemberCNT4 , SUM(VisitCNT5) AS VisitCNT5 , SUM(GRMemberCNT5) AS GRMemberCNT5 , SUM(VisitCNT6) AS VisitCNT6 , SUM(GRMemberCNT6) AS GRMemberCNT6 , SUM(VisitCNT7) AS VisitCNT7 , SUM(GRMemberCNT7) AS GRMemberCNT7 , SUM(VisitCNT8) AS VisitCNT8 , SUM(GRMemberCNT8) AS GRMemberCNT8 , (SUM(VisitCNT1) + SUM(VisitCNT2) + SUM(VisitCNT3) + SUM(VisitCNT4) + SUM(VisitCNT5) + SUM(VisitCNT6) + SUM(VisitCNT7) + SUM(VisitCNT8)) AS VisitCNT , (SUM(GRMemberCNT1) + SUM(GRMemberCNT2) + SUM(GRMemberCNT3) + SUM(GRMemberCNT4) + SUM(GRMemberCNT5) + SUM(GRMemberCNT6) + SUM(GRMemberCNT7) + SUM(GRMemberCNT8)) AS TotalGRMemberCNT FROM ( SELECT GR.VisitDate ,CASE WHEN TTT.TeamCode = 'K01193' THEN GR.VisitCNT ELSE 0 END VisitCNT1 ,CASE WHEN TTT.TeamCode = 'K00012' THEN GR.VisitCNT ELSE 0 END VisitCNT2 ,CASE WHEN TTT.TeamCode = 'K01024' THEN GR.VisitCNT ELSE 0 END VisitCNT3 ,CASE WHEN TTT.TeamCode = 'K01251' THEN GR.VisitCNT ELSE 0 END VisitCNT4 ,CASE WHEN TTT.TeamCode = 'K00015' THEN GR.VisitCNT ELSE 0 END VisitCNT5 ,CASE WHEN TTT.TeamCode = 'K00090' THEN GR.VisitCNT ELSE 0 END VisitCNT6 ,CASE WHEN TTT.TeamCode = 'K00513' THEN GR.VisitCNT ELSE 0 END VisitCNT7 ,CASE WHEN TTT.TeamCode = 'K00092' THEN GR.VisitCNT ELSE 0 END VisitCNT8
,CASE WHEN TTT.TeamCode = 'K01193' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT1 ,CASE WHEN TTT.TeamCode = 'K00012' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT2 ,CASE WHEN TTT.TeamCode = 'K01024' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT3 ,CASE WHEN TTT.TeamCode = 'K01251' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT4 ,CASE WHEN TTT.TeamCode = 'K00015' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT5 ,CASE WHEN TTT.TeamCode = 'K00090' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT6 ,CASE WHEN TTT.TeamCode = 'K00513' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT7 ,CASE WHEN TTT.TeamCode = 'K00092' THEN GR.TotalGRMemberCNT ELSE 0 END GRMemberCNT8 FROM [XBOLTADM].[TW_GR_VISIT_LOG] GR LEFT JOIN XBOLTADM.TB_TEAM_TXT TTT ON TTT.TeamID = GR.GRTeam AND TTT.LanguageID = 1042 WHERE GR.DataType = 'DAY'
AND GR.VisitDate >= #{startDate}
AND GR.VisitDate <= #{endDate}
)AA )BB

SELECT
TOP ${top}
Row_Number()OVER(Order by TI.LastUpdated DESC) as RNUM , TI.ItemID , TI.Identifier , TIA.PlainText AS ItemName , ISNULL(CONVERT(char(10), TI.LastUpdated, 120),'') as LastUpdated , TDT.Name AS TypeCode , TTT.Name AS TeamName , TM.Name AS AuthorName , TD.Name AS StatusName FROM XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = 1042 LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDT on TI.ItemTypeCode = TDT.TypeCode AND TDT.LanguageID = 1042 AND TDT.Category = 'OJ' LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTT ON TM.TeamID = TTT.TeamID AND TTT.LanguageID = 1042 LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.Status = TD.TypeCode AND TD.LanguageID = 1042 AND TD.Category = 'ITMSTS' LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS on TI.ClassCode = TCLS.ItemClassCode LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TCS.ItemID = TI.ItemID AND TCS.ChangeSetID = TI.CurChangeSet WHERE TI.Deleted != 1 AND TI.CategoryCode = 'OJ' AND TI.LastUpdated BETWEEN DATEADD(MONTH, -6, GETDATE()) AND GETDATE() AND TCLS.ChangeMgt = '1' AND TCS.ChangeSetID IS NOT NULL

