INSERT INTO AMS.IAMS.dbo.TBL_BATCH_ERROR_LOG_INFO ( 
	AFFILIATE_ID, HOSTNAME, IP, ALARM_LEVEL, MESSAGE, FAULT_STATUS, FILTER_YN, INSERT_DATE, ALARM_TIME
) VALUES ( '0001', 'PAL', #{IpAddress}, '01', 'PAL|프로세스자산화|exeSYSinterface|IAM Role List IF Job|'+ CONVERT(CHAR(19), getdate(), 20)+'|'+CONVERT(CHAR(19), getdate(), 20)+'|No value for Result', '0', 'N', getdate(), CONVERT(CHAR(19), getdate(), 20) )

mapper.select:
Select TOP 5 TCS.ChangeSetID , TCS.ProjectID , TI.Identifier , TIA.PlainText AS ItemName , TCS.ItemID , TCS.AuthorTeamID , ISNULL(TTT.Name,'') AS AuthorTeamName , ISNULL(TTT.TeamCode,'') AS AuthorTeamCode , TCS.AuthorID , TM.Name As AuthorName , ISNULL(CONVERT(char(10),TCS.ValidFrom, 120),'') as ValidFrom FROM XBOLTADM.TB_CHANGE_SET TCS LEFT OUTER JOIN XBOLTADM.TB_ITEM TI on TCS.ItemID = TI.ItemID AND TCS.ChangeSetID = CASE TI.ReleaseNo WHEN '0' THEN TI.CurChangeSet ELSE TI.ReleaseNo END LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA on TCS.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM on TCS.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTT on TCS.AuthorTeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS on TI.ClassCode = TCLS.ItemClassCode Where TI.ItemID Not IN (Select ItemID from XBOLTADM.TB_ITEM Where Deleted = '1' AND Status = 'NEW1' AND CategoryCode = 'OJ' ) AND TI.ItemID In (Select ToItemID from XBOLTADM.TB_ITEM Where CategoryCode = 'ST1') AND TCS.Status = #{Status}
AND TCLS.ItemClassCode IN (
#{item}
)
ORDER BY TCS.ValidFrom DESC

Select Row_Number()OVER(Order by TI.Identifier) AS RNUM , TI.ItemID , ISNULL(TI.Identifier, '') AS Identifier , ISNULL(TIA.PlainText, '') AS ItemName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , TDC.Name AS ClassName , TI.Status, TDS.Name As StatusNM , ISNULL(Convert(nvarchar(20),TIAZ4.PlainText, 120),'') As ZAT0004 , ISNULL(TIAZ5.PlainText,'') AS ZAT0005Code , ISNULL(CONVERT(char(10), TI.LastUpdated, 120),'') as LastUpdated , ISNULL(TATL.Value,'') AS ZAT0005 , ISNULL(TIAZ6.PlainText,'') AS ZAT0006 , ISNULL(TM.Name,'') AS AuthorName , ISNULL(TMT.Name, '') AS OwnerTeamName From XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDC ON TDC.TypeCode = TI.ClassCode And TDC.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDS ON TI.Status = TDS.TypeCode AND TDS.Category = 'ITMSTS' AND TDS.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ4 ON TIAZ4.ItemID = TI.ItemID And TIAZ4.AttrTypeCode = 'ZAT0004' And TIAZ4.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ5 ON TIAZ5.ItemID = TI.ItemID And TIAZ5.AttrTypeCode = 'ZAT0005' And TIAZ5.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL ON TATL.AttrTypeCode = 'ZAT0005' And TATL.LanguageID = #{defaultLang} And TATL.LovCode = TIAZ5.PlainText LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ6 ON TIAZ6.ItemID = TI.ItemID And TIAZ6.AttrTypeCode = 'ZAT0006' And TIAZ5.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT ON TMT.TeamID = TI.OwnerTeamID And TMT.LanguageID = #{languageID} Where TI.Deleted != 1 AND TI.CategoryCode IN ('OJ' ,'VAR') ANd TI.ClassCode = #{classCode}
And Left(ISNULL(TI.Identifier,''),2) = #{L1}
AND (TI.Identifier IS NOT NULL OR TI.Identifier != '')

Select 
	TI.ItemID, TI.Identifier, ISNULL(TIA1.PlainText,'') AS AT00001 
	, ISNULL(TIAZ10.PlainText,'') AS ZAT4010 
	, ISNULL(TIAZ15.PlainText,'') AS ZAT4015
	, ISNULL(TM.Name,'') AS ZAT4015_Text
	, ISNULL(TIAZ11.PlainText,'') AS ZAT4011
	, ISNULL(TIAZ16.PlainText,'') AS ZAT4016
	, TI.AuthorID
	, TI.LockOwner
	, TI.Blocked
From XBOLTADM.Tb_ITEM TI
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 ON TIA1.ItemID = TI.ItemID And TIA1.AttrTypeCode = 'AT00001' And TIA1.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ10 ON TIAZ10.ItemID = TI.ItemID And TIAZ10.AttrTypeCode = 'ZAT4010' And TIAZ10.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ15 ON TIAZ15.ItemID = TI.ItemID And TIAZ15.AttrTypeCode = 'ZAT4015' And TIAZ15.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON CONVERT(VARCHAR(10),TM.MemberID) = TIAZ15.PlainText
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ11 ON TIAZ11.ItemID = TI.ItemID And TIAZ11.AttrTypeCode = 'ZAT4011' And TIAZ11.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIAZ16 ON TIAZ16.ItemID = TI.ItemID And TIAZ16.AttrTypeCode = 'ZAT4016' And TIAZ16.LanguageID = #{languageID}
Where TI.ItemID = #{itemID}

