INSERT INTO XBOLTDLM.IM_SYNC_EMP ( USERID, USERNAME, USERENNAME, EMAIL, MOBILE, DEPTCODE, DEPTNAME, EMPNO, GRADECODE, GRADENAME, POSITIONCODE, POSITIONNAME, RETIREDATE, COMPANYCODE, COMPANYNAME, TITCODE, TITNAME, COMPTEL, STATUS, SORTNUM, JOBTYPE
) VALUES ( #{USERID}, #{USERNAME}, #{USERENNAME}, #{USERID}, #{MOBILE}, #{DEPTCODE}, #{DEPTNAME}, #{EMPNO}, #{GRADECODE}, #{GRADENAME}, #{POSITIONCODE}, #{POSITIONNAME}, #{RETIREDATE}, #{COMPANYCODE}, #{COMPANYNAME}, #{TITCODE}, #{TITNAME}, #{COMPTEL}, #{STATUS}, #{SORTNUM}, #{JOBTYPE}
)

mapper.select:
SELECT Row_Number()OVER(ORDER BY m.Name ASC ) as RNUM , 0 AS CHK,m.CompanyID,TM.TeamType, m.MemberID,m.LoginID,m.EmployeeNum, m.Name AS UserName ,M.TeamID,TM.TeamCode,TT.NAME AS TeamName ,m.Authority ,ISNULL(TDML.Name, '') AS AuthorityName, CASE WHEN AuthorID IS NOT NULL THEN 'Y' ELSE 'N' END AS 'ManagerCheck', ISNULL (( SELECT COUNT(CS.ChangeSetID) FROM XBOLTADM.TB_CHANGE_SET AS CS WHERE CS.AuthorID = m.MemberID AND CS.ChangeType = 'NEW' AND CS.ItemClassCode = 'CL01005' AND projectID != 3
AND CS.CreationTime BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0' ) AS 'ProcNewCnt', ISNULL (( SELECT COUNT(CS.ChangeSetID) FROM XBOLTADM.TB_CHANGE_SET AS CS WHERE CS.AuthorID = m.MemberID AND CS.ChangeType = 'MOD' AND CS.ItemClassCode = 'CL01005' AND projectID != 3
AND CS.CreationTime BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0' ) AS 'ProcModCnt', ISNULL (( SELECT COUNT(*) FROM XBOLTADM.TB_BOARD AS BD WHERE BD.RegUserID = m.MemberID AND BD.BoardMgtID = 'BRD0002'
AND BD.RegDT BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0' ) AS 'BrdCnt', ISNULL (( SELECT COUNT(*) FROM XBOLTADM.TB_VISIT_LOG AS v INNER JOIN XBOLTADM.TB_ITEM AS itm ON v.ItemID = itm.ItemID WHERE v.MemberID = m.MemberID AND itm.ClassCode = 'CL01005'
AND TIME BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0') AS 'L4Visit', ISNULL((SELECT COUNT(DISTINCT im.ItemID) AS ItemCount FROM XBOLTADM.TB_ITEM AS im WHERE ClassCode = 'CL01005' AND Identifier IS NOT NULL AND im.LastUser = m.MemberID
AND im.LastUpdated BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
GROUP BY LastUser),'0') AS 'ProcUpdcnt'
FROM XBOLTADM.TB_MEMBER AS m INNER join XBOLTADM.TB_TEAM_TXT AS TT on m.TeamID =TT.TeamID LEFT JOIN (SELECT DISTINCT AuthorID FROM XBOLTADM.TB_ITEM WHERE ClassCode = 'CL01005' AND Identifier IS NOT NULL) AS ITM ON M.MemberID = ITM.AuthorID LEFT JOIN XBOLTADM.TB_DICTIONARY TDML ON M.MLVL = TDML.TypeCode LEFT JOIN XBOLTADM.TB_TEAM TM ON TM.TeamID = M.TeamID WHERE TT.LanguageID = #{languageID} AND M.UserType = 1 AND M.Active = 1 AND TDML.LanguageID = #{languageID}
GROUP BY m.MemberID,m.LoginID,m.EmployeeNum,m.Name,M.TeamID,TM.TeamCode,TT.NAME,ITM.AuthorID,m.Authority,TDML.Name,m.CompanyID,TM.TeamType ORDER BY RNUM

SELECT Row_Number()OVER(ORDER BY ITM.Identifier ASC ) as RNUM , LEFT(ITM.Identifier,2) AS L1 , LEFT(ITM.Identifier,4) AS L2, LEFT(ITM.Identifier,6) AS L3, ITM.Identifier AS L4 , ATR.PlainText AS 'L4Name' , MM2.NAME AS 'ProcManager', TX.Name AS 'TeamName', MM1.NAME AS 'TeamManager', ISNULL(( SELECT MBR.Name FROM XBOLTADM.TB_TEAM TM2 LEFT JOIN XBOLTADM.TB_MEMBER MBR ON MBR.MemberID = TM2.ManagerID WHERE TM2.TeamID = TM.ParentID AND MBR.JobClassCode = 'D020' ) ,NULL)AS 'TeamExecutiv', ISNULL((SELECT CASE WHEN IDM.DimValueID ='CP1' THEN 'Y' ELSE 'N' END AS TYPE FROM XBOLTADM.TB_ITEM_DIM IDM WHERE IDM.ItemID = ITM.ItemID AND IDM.DimValueID ='CP1' AND IDM.DimTypeID ='123720' ),'N')AS 'CProc' , ISNULL (( SELECT STRING_AGG(TT.Name, ', ') AS 'Name' FROM XBOLTADM.TB_TEAM_ROLE AS TR1 inner JOIN XBOLTADM.TB_TEAM_TXT AS TT ON TT.TeamID = TR1.TeamID WHERE TR1.ItemID = ITM.ItemID and TR1.TeamRoleType = 'EXE' and tt.LanguageID = #{languageID} AND TT.NAME not LIKE '%PE영업팀%' ),' ' ) AS 'ExeDept' , ISNULL (( SELECT STRING_AGG(TT.Name, ', ') AS 'Name' FROM XBOLTADM.TB_TEAM_ROLE AS TR2 inner JOIN XBOLTADM.TB_TEAM_TXT AS TT ON TT.TeamID = TR2.TeamID WHERE TR2.ItemID = ITM.ItemID and TR2.TeamRoleType = 'REL' and tt.LanguageID = #{languageID} AND TT.NAME not LIKE '%PE영업팀%' ),' ' ) AS 'RelDept' , ISNULL (( SELECT COUNT(*) FROM XBOLTADM.TB_BOARD AS BD WHERE BD.ItemID = ITM.ItemID AND BD.BoardMgtID = 'BRD0002'
AND BD.RegDT BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0' ) AS 'Comment', ISNULL (( SELECT COUNT(*) FROM XBOLTADM.TB_VISIT_LOG AS v WHERE V.ItemID = ITM.ItemID
AND TIME BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0') AS 'L4Visit'
,ISNULL (( SELECT COUNT(*) FROM XBOLTADM.TB_CHANGE_SET AS CS2 WHERE CS2.ItemID = ITM.ItemID AND CS2.ChangeType = 'NEW' AND CS2.ItemClassCode = 'CL01005'
AND CS2.CreationTime BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0' ) AS 'ProcNewCnt',
ISNULL (( SELECT COUNT(*) FROM XBOLTADM.TB_CHANGE_SET AS CS3 WHERE CS3.ItemID = ITM.ItemID AND CS3.ChangeType = 'MOD' AND CS3.ItemClassCode = 'CL01005'
AND CS3.CreationTime BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt})
),'0' ) AS 'ProcModCnt' , (CASE WHEN ITM.LastUpdated BETWEEN #{StartDt} AND DATEADD(DAY, 1, #{EndDt}) THEN 1 ELSE 0 END) AS 'ProcUpd' FROM XBOLTADM.TB_ITEM AS ITM INNER JOIN XBOLTADM.TB_CHANGE_SET AS CS ON ITM.CurChangeSet = CS.ChangeSetID LEFT JOIN XBOLTADM.TB_ITEM_ATTR AS ATR ON ITM.ItemID = ATR.ItemID LEFT JOIN XBOLTADM.TB_TEAM_TXT AS TX ON TX.TeamID = ITM.OwnerTeamID LEFT JOIN XBOLTADM.TB_TEAM AS TM ON TM.TeamID = ITM.OwnerTeamID LEFT JOIN.XBOLTADM.TB_MEMBER AS MM1 ON MM1.MemberID = TM.ManagerID LEFT JOIN.XBOLTADM.TB_MEMBER AS MM2 ON MM2.MemberID = ITM.AuthorID WHERE ITM.ClassCode = 'CL01005' AND ITM.Status NOT LIKE '%DEL1%' AND CS.ChangeType NOT LIKE '%DEL%' AND ITM.Identifier IS NOT NULL AND ITM.ProjectID !='5' AND ITM.Identifier NOT LIKE '%Z%' AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{languageID} AND TX.LanguageID = #{languageID}
ORDER BY RNUM

