SELECT TIO.SystemType AS SYS ,TIO.ObjectID AS ID ,TIO.Seq_NO AS ATNF092 ,TIO.PObjectID AS ParentID ,TIO.AT00000 AS ATNF094 ,TIO.AT00001 AS ATNF091
,TIO.ATNF001 AS ATNF001 ,TIO.ATNF002 AS ATNF002 ,TIO.ATNF003 AS ATNF003 ,'호출' AS Action ,CONVERT(varchar, GETDATE(), 23) AS UpdatedOnDate ,'05:05:00' AS UpdatedOnTime
FROM XBOLTADM.TI_ITEM_ATTR_ORG TIO WHERE TIO.SystemType = #{systemType}

SELECT 
		distinct TATA.SortNum
		,TATA.AttrTypeCode AS AttrTypeCode
		, ISNULL(TD.Name, '') AS Name
		, CASE TAT.DataType
			WHEN 'LOV' THEN TATL.Value
			WHEN 'MLOV' THEN ''
			ELSE 
			
				ISNULL(ISNULL(TIA.PlainText, TIA2.PlainText),'')
				ISNULL(TIA.PlainText,'')
			
		  END PlainText
		, CASE TAT.DataType 
			WHEN 'MLOV' Then ''
			ELSE ISNULL(TIA.LovCode, '') END  AS LovCode
		, ISNULL(TATL.AttrTypeCode, '') AS BaseLovCode
		, TAT.DataType
		, TAT.IsComLang
		, TAT.HTML
		, ISNULL(TATA.Mandatory, '') AS Mandatory
		, ISNULL(TAT.Editable, '') AS Editable
		, TATA.Link
		, TM.URL
		, ISNULL(TATA.AreaHeight, '20') AS AreaHeight
	FROM 
		XBOLTADM.TB_ATTR_TYPE_ALLOCATION TATA
		
			
				Left Outer Join XBOLTADM.TB_ITEM_ATTR_REV TIA ON TATA.AttrTypeCode = TIA.AttrTypeCode AND TIA.ItemID = #{s_itemID} And TIA.ChangeSetID = #{changeSetID} AND CONVERT(VARCHAR, TIA.LASTUPDATED, 23) = #{lastUpdatedOnDate}
				
					AND TIA.LanguageID = #{languageID}
					AND TIA.LanguageID = #{defaultLang}
				
				
				Left Outer Join XBOLTADM.TB_ITEM_ATTR_REV TIA2 ON TATA.AttrTypeCode = TIA2.AttrTypeCode AND TIA2.ItemID = #{s_itemID} And TIA2.ChangeSetID = #{releaseNo} AND CONVERT(VARCHAR, TIA2.LASTUPDATED, 23) = #{lastUpdatedOnDate}
				
					AND TIA2.LanguageID = #{languageID}
					AND TIA2.LanguageID = #{defaultLang}
				
				
			
			
				Inner Join XBOLTADM.TB_ITEM_ATTR_REV TIA ON TATA.AttrTypeCode = TIA.AttrTypeCode AND TIA.ItemID = #{s_itemID} And TIA.ChangeSetID = #{changeSetID} AND CONVERT(VARCHAR, TIA.LASTUPDATED, 23) = #{updatedOnDate}
				
					AND TIA.LanguageID = #{languageID}
					AND TIA.LanguageID = #{defaultLang}
				
				
				Inner Join XBOLTADM.TB_ITEM_ATTR_REV TIA2 ON TATA.AttrTypeCode = TIA2.AttrTypeCode AND TIA2.ItemID = #{s_itemID} And TIA2.ChangeSetID = #{releaseNo} AND CONVERT(VARCHAR, TIA2.LASTUPDATED, 23) = #{updatedOnDate}
				
					AND TIA2.LanguageID = #{languageID}
					AND TIA2.LanguageID = #{defaultLang}
				
				
			
		
		Left Outer Join XBOLTADM.TB_DICTIONARY TD on TATA.AttrTypeCode = TD.TypeCode 
		
			AND TD.LanguageID = #{loginLangType}
			AND TD.LanguageID = #{languageID}
		
		Left Outer join	XBOLTADM.TB_ATTR_TYPE_LOV TATL	on TATA.AttrTypeCode  = TATL.AttrTypeCode AND TIA.LovCode = TATL.LovCode AND TATL.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT on TATA.AttrTypeCode = TAT.AttrTypeCode 
		Left Outer Join XBOLTADM.TB_MENU TM ON TATA.Link = TM.MenuID					
	WHERE
		TATA.ItemClassCode = (SELECT ClassCode From XBOLTADM.TB_ITEM WHERE ItemID = #{s_itemID})
		
		AND TAT.AttrTypeCode = #{AttrTypeCode}
		
		
		AND TAT.AttrTypeCode IN ${AttrTypeCodes}
		
		
		AND TAT.IsComLang = 1 AND TAT.DataType != 'LOV'
		
		
		AND TAT.Editable = #{Editable}
		
		
	ORDER BY
		TATA.SortNum ASC

