 		UPDATE	XBOLTADM.TB_MEMBER
 		SET 	
			AlarmOption = #{alarmOption}			
 		WHERE
 			MemberID = #{memberID}

mapper.select:
SELECT LovCode,AttrTypeCode,Value,RefLovCode
FROM XBOLTADM.TB_ATTR_TYPE_LOV 
WHERE LanguageID = #{languageID}　
	AND AttrTypeCode = #{atrTypeCode}　
	
	AND Value = #{Name}
	
	
		AND LovCode =#{LovCode}


SELECT TIH.L1ItemID, TIA.PlainText AS L1Name　
	,tih.L2ItemID,TIA2.PlainText AS L2Name 
	,TIH.ItemID AS L3ItemID, TIA3.PlainText AS L3Name
	,TIH.ItemClassCode,TIH.ItemTypeCode
FROM XBOLTADM.TW_ITEM_HIER AS TIH  INNER JOIN XBOLTADM.TB_ITEM_ATTR AS TIA ON TIH.L1ItemID = TIA.ItemID AND TIA.LanguageID = #{languageID}
	 LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS TIA2 ON TIH.L2ItemID = TIA2.ItemID AND TIA2.LanguageID = #{languageID}
	 LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR AS TIA3 ON TIH.ItemID = TIA3.ItemID AND TIA3.LanguageID = #{languageID}
WHERE   TIH.ItemID = #{curItemID}


SELECT Value AS siteNM , LovCode AS CODE
FROM XBOLTADM.TB_ATTR_TYPE_LOV 
WHERE AttrTypeCode = 'ZAT01010' AND LovCode = #{defDimValueID} AND LanguageID = #{languageID}

SELECT LovCode,Value
FROM XBOLTADM.TB_ATTR_TYPE_LOV 
WHERE 1=1 AND AttrTypeCode='ZAT01080' AND LanguageID = '1042' AND LovCode = #{siteCode}

WITH TeamRoleData AS ( SELECT ROW_NUMBER() OVER ( ORDER BY CASE TTR.TeamRoleType WHEN 'R' THEN 1 WHEN 'A' THEN 2 WHEN 'S' THEN 3 WHEN 'I' THEN 4 WHEN 'C' THEN 5 ELSE 6 END, TD.SortNum, XBOLTADM.fn_GetMyAbsPathForOrg(TMT.TeamID , #{languageID}), TMT.Name ) AS RNUM, 0 AS CHK, TTR.TeamRoleID, ISNULL(TT.TeamCode,'') AS TeamCode, ISNULL(TMT.Name,'') AS TeamNM, XBOLTADM.fn_GetMyAbsPathForOrg(TMT.TeamID , #{languageID}) AS TeamPath, ISNULL(TD.Name,'') AS TeamRoleNM, ISNULL(CONVERT(char(10), TTR.AssignedDate, 111), '') AS AssignedDate, ISNULL(CONVERT(char(10), TTR.LastUpdated, 111), '') AS LastUpdated, ISNULL(TTR.RoleManagerID, TT.RoleManagerID) AS RoleManagerID, ISNULL(TM.Name, ISNULL(TM1.Name,'N/A')) + CASE WHEN ISNULL(TM.NameEN,'') != '' THEN '(' + ISNULL(TM.NameEN,'') + ')' WHEN ISNULL(TM1.NameEN,'') != '' THEN '(' + ISNULL(TM1.NameEN,'') + ')' ELSE '' END AS RoleManagerNM, TTR.ItemID, TTR.TeamRoleType, TD.SortNum AS SortNum, TTR.TeamID, TT.ManagerID AS TeamManagerID, TT.RoleManagerID AS curRoleManagerID, TT.RoleManagerID AS rctMemberID, ISNULL(TM.Name, ISNULL(TM1.Name,'N/A')) AS rctMemberNM, TTR.RoleDescription, ISNULL(TMRSTS.Name,'') AS TMRStatusNM, ISNULL(TTR.Assigned,'') AS Assigned,
CASE TTR.TeamRoleType WHEN 'R' THEN 1 WHEN 'A' THEN 2 WHEN 'S' THEN 3 WHEN 'I' THEN 4 WHEN 'C' THEN 5 ELSE 6 END AS RolePriority FROM XBOLTADM.TB_TEAM_ROLE TTR LEFT JOIN XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID LEFT JOIN XBOLTADM.TB_TEAM_TXT TMT ON TMT.TeamID = TTR.TeamID AND TMT.LanguageID = #{languageID} LEFT JOIN XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = TTR.TeamRoleType AND TD.Category = 'TEAMROLETP' AND TD.LanguageID = #{languageID} LEFT JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = TTR.RoleManagerID LEFT JOIN XBOLTADM.TB_MEMBER TM1 ON TM1.MemberID = TT.RoleManagerID LEFT JOIN XBOLTADM.TB_DICTIONARY TMRSTS ON TMRSTS.TypeCode = TTR.Assigned AND TMRSTS.Category = 'TMRSTS' AND TMRSTS.LanguageID = #{languageID} WHERE TTR.ItemID IN ( SELECT CAST(#{itemID} AS bigint) UNION ALL SELECT ToItemID FROM XBOLTADM.TB_ITEM WITH (NOLOCK) WHERE FromItemID = #{itemID} AND CategoryCode = 'ST1' ) AND ( RTRIM(TMT.Name) LIKE N'%팀' OR RTRIM(TMT.Name) LIKE N'%부' )
AND TT.CompanyID = #{companyID}
AND TTR.TeamRoleType = #{roleType}
AND TTR.TeamRoleType IN (${roleTypes})
AND TTR.AssignmentType = #{assignmentType}
AND TTR.Assigned != 0 AND TTR.Assigned > 0
AND TTR.Assigned IN (${asgnOption})
), Ranked AS ( SELECT TeamRoleData.*, DENSE_RANK() OVER ( PARTITION BY TeamRoleData.TeamCode ORDER BY TeamRoleData.RolePriority ) AS rk_in_team FROM TeamRoleData ), Result AS ( SELECT *, ROW_NUMBER() OVER ( PARTITION BY TeamCode, RolePriority ORDER BY SortNum, TeamPath, TeamNM ) AS rn_dedup FROM Ranked WHERE rk_in_team = 1 ) SELECT RNUM, CHK, TeamRoleID, TeamCode, TeamNM, TeamPath, TeamRoleNM, AssignedDate, LastUpdated, RoleManagerID, RoleManagerNM, ItemID, TeamRoleType, SortNum, TeamID, TeamManagerID, curRoleManagerID, rctMemberID, rctMemberNM, RoleDescription, TMRStatusNM, Assigned FROM Result WHERE rn_dedup = 1 ORDER BY RNUM, TeamCode, RolePriority, SortNum, TeamPath, TeamNM ASC
